# ============================================================
# Compare classifiers across feature sets
#
# Models:
#   1. Elastic Net
#   2. SVM
#   3. Random Forest
#
# Feature sets:
#   1. global_endmotif_256
#   2. regional_mds_167
#   3. bioanalyzer_10bp_length
#
# This script reads standardized outputs generated by:
#   02_run_svm_nested_cv.R
#   03_run_rf_nested_cv.R
#   04_run_elastic_net_nested_cv.R
#
# Usage:
#   Rscript scripts/07_classification/05_compare_classifiers.R
# ============================================================

suppressPackageStartupMessages({
  library(readr)
  library(dplyr)
  library(tidyr)
  library(stringr)
  library(ggplot2)
  library(forcats)
  library(scales)
})

# ============================================================
# 1. Paths
# ============================================================

out_dir <- "results/tables/classification/classifier_comparison"
