# ============================================================
# 3. Helper functions
# ============================================================

save_plot <- function(plot_object, filename, width, height, dpi = 300) {

  ggsave(
    filename = file.path(fig_dir, paste0(filename, ".png")),
    plot = plot_object,
    width = width,
    height = height,
    units = "in",
    dpi = dpi,
    bg = "white"
  )

  ggsave(
    filename = file.path(fig_dir, paste0(filename, ".pdf")),
    plot = plot_object,
    width = width,
    height = height,
    units = "in",
    device = "pdf"
  )
}

read_model_summary <- function(model, feature_set) {

  feature_label <- feature_labels[[feature_set]]

  if (model == "Elastic Net") {
    path <- file.path(
      "results/tables/classification/elastic_net",
      feature_set,
      "elastic_net_results_summary.csv"
    )
  }

  if (model == "SVM") {
    path <- file.path(
      "results/tables/classification/svm",
      feature_set,
      "svm_5methods_results_summary.csv"
    )
  }

  if (model == "Random Forest") {
    path <- file.path(
      "results/tables/classification/random_forest",
      feature_set,
      "rf_5methods_results_summary.csv"
    )
  }

  if (!file.exists(path)) {
    warning("Missing summary file: ", path)
    return(NULL)
  }

  df <- read_csv(path, show_col_types = FALSE)

  if (!"Method" %in% colnames(df)) {
    df$Method <- model
  }

  if (model == "Elastic Net") {
    df$Method <- "Elastic Net"
  }

  required_cols <- c(
    "Task",
    "Method",
    "Pooled_AUC",
    "Fold_AUC_mean",
    "Fold_AUC_sd",
    "Accuracy_mean",
    "Balanced_Accuracy_mean",
    "Sensitivity_mean",
    "Specificity_mean",
    "PPV_mean",
    "NPV_mean",
    "F1_mean",
    "N_Selected_Features_mean"
  )

  for (cc in required_cols) {
    if (!cc %in% colnames(df)) {
      df[[cc]] <- NA_real_
    }
  }

  df %>%
    mutate(
      Model = model,
      Feature_Set_ID = feature_set,
      Feature_Set = feature_label,
      Classifier = paste(Model, Feature_Set, Method, sep = " | "),
      Classifier_short = case_when(
        Model == "Elastic Net" ~ paste("EN", Feature_Set),
        Model == "SVM" ~ paste("SVM", Feature_Set, Method, sep = " - "),
        Model == "Random Forest" ~ paste("RF", Feature_Set, Method, sep = " - "),
        TRUE ~ Classifier
      )
    ) %>%
    select(
      Model,
      Feature_Set_ID,
      Feature_Set,
      Method,
      Classifier,
      Classifier_short,
      all_of(required_cols)
    )
}

safe_scale <- function(x) {
  if (all(is.na(x)) || sd(x, na.rm = TRUE) == 0) {
    return(rep(0, length(x)))
  }
  as.numeric(scale(x))
}

format_region <- function(x) {
  ifelse(
    str_detect(x, "^regional_MDS_chr[^_]+_\\d+_\\d+$"),
    x %>%
      str_replace("^regional_MDS_", "") %>%
      str_replace("^(chr[^_]+)_(\\d+)_(\\d+)$", "\\1:\\2-\\3"),
    ifelse(
      str_detect(x, "^chr[^_]+_\\d+_\\d+$"),
      str_replace(x, "^(chr[^_]+)_(\\d+)_(\\d+)$", "\\1:\\2-\\3"),
      x
    )
  )
}

clean_feature_label <- function(feature, feature_set) {

  feature <- as.character(feature)

  if (feature_set == "Regional MDS") {
    feature <- str_replace(feature, "^regional_MDS_", "")
    return(format_region(feature))
  }

  if (feature_set == "Bioanalyzer length bins") {
    feature <- str_replace(feature, "^length_", "")
    feature <- str_replace(feature, "bp$", " bp")
    feature <- str_replace_all(feature, "_", "-")
    return(feature)
  }

  feature
}

# ============================================================
# 4. Read all model summaries
# ============================================================

comparison_df <- bind_rows(
  lapply(feature_sets, function(fs) read_model_summary("Elastic Net", fs)),
  lapply(feature_sets, function(fs) read_model_summary("SVM", fs)),
  lapply(feature_sets, function(fs) read_model_summary("Random Forest", fs))
) %>%
  mutate(
    Task = factor(Task, levels = task_order),
    Model = factor(Model, levels = model_order),
    Feature_Set = factor(Feature_Set, levels = feature_order),
    Method = factor(Method, levels = method_order)
  )

if (nrow(comparison_df) == 0) {
  stop("No classifier summary files were found.")
}

write_csv(
  comparison_df,
  file.path(out_dir, "all_classifier_results_combined.csv")
)

cat("\nRows per model and feature set:\n")
