# ============================================================
# 5. Ranked summary table
# ============================================================

ranked_summary <- comparison_df %>%
  mutate(
    rank_score =
      Pooled_AUC +
      Balanced_Accuracy_mean +
      Sensitivity_mean +
      Specificity_mean +
      F1_mean -
      Fold_AUC_sd
  ) %>%
  arrange(desc(rank_score)) %>%
  select(
    Task,
    Model,
    Feature_Set,
    Method,
    Classifier_short,
    Pooled_AUC,
    Fold_AUC_mean,
    Fold_AUC_sd,
    Accuracy_mean,
    Balanced_Accuracy_mean,
    Sensitivity_mean,
    Specificity_mean,
    PPV_mean,
    NPV_mean,
    F1_mean,
    N_Selected_Features_mean,
    rank_score
  )

write_csv(
  ranked_summary,
  file.path(out_dir, "ranked_classifier_summary.csv")
)

# ============================================================
