      Pooled_AUC,
      .fun = mean,
      .na_rm = TRUE
    )
  )

p_auc_heatmap <- ggplot(
  auc_heatmap_df,
  aes(x = Task, y = Classifier_short, fill = Pooled_AUC)
) +
  geom_tile(color = "white", linewidth = 0.4) +
  geom_text(aes(label = sprintf("%.3f", Pooled_AUC)), size = 2.7) +
  scale_fill_gradientn(
    colours = heatmap_colors,
    values = scales::rescale(c(0, 0.5, 0.75, 0.90, 1.00)),
    limits = c(0, 1),
    name = "Pooled AUC"
  ) +
  labs(
    title = "Classifier comparison by pooled AUC",
    subtitle = "Elastic Net, SVM, and Random Forest across three feature sets",
    x = "Classification task",
    y = "Classifier"
  ) +
  theme_bw(base_size = 13, base_family = plot_font) +
  theme(
    axis.text.x = element_text(angle = 45, hjust = 1),
    axis.text.y = element_text(size = 7, color = "black"),
    panel.grid = element_blank(),
    plot.title = element_text(face = "bold", hjust = 0.5),
    plot.subtitle = element_text(hjust = 0.5, color = "grey35")
  )

save_plot(
